import androidx.core.content.ContextCompat

interface NativeBridgeListener {
    fun onCameraRequested()
    fun onGetStorage(key: String): String?
    fun onSetStorage(key: String, value: String)
    fun onClearStorage()
    fun onPushNotificationRequested(title: String, body: String)
}

class HybridWebViewActivity : ComponentActivity(), NativeBridgeListener {
    private lateinit var webView: WebView
    private val storage by lazy { getSharedPreferences("hybrid_webview_storage", Context.MODE_PRIVATE) }
    private var pendingCameraPermissionCallback: (() -> Unit)? = null
    private var pendingJsResult: ValueCallback<String>? = null

    private val cameraPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { granted ->
        if (granted) {
            pendingCameraPermissionCallback?.invoke()
        } else {
            pendingJsResult?.onReceiveValue("{\"success\":false,\"error\":\"Camera permission denied\"}")
        }
        pendingCameraPermissionCallback = null
        pendingJsResult = null
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        webView = WebView(this)
        webView.layoutParams = FrameLayout.LayoutParams(
            FrameLayout.LayoutParams.MATCH_PARENT,
            FrameLayout.LayoutParams.MATCH_PARENT
        )

        setContentView(webView)
        configureWebView(webView)

        webView.loadUrl("https://your-mobile-web-app.example.com")
    }

    private fun configureWebView(webView: WebView) {
        with(webView.settings) {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = true
            setSupportZoom(false)
            loadWithOverviewMode = true
            useWideViewPort = true
            allowFileAccess = false
            allowContentAccess = false
            mediaPlaybackRequiresUserGesture = false
            cacheMode = WebSettings.LOAD_DEFAULT
        }

        webView.addJavascriptInterface(AndroidBridge(this), "AndroidBridge")

        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
                return false
            }
        }

        webView.webChromeClient = object : WebChromeClient() {
            override fun onPermissionRequest(request: PermissionRequest) {
                runOnUiThread {
                    val resources = request.resources?.toSet().orEmpty()
                    if (resources.contains(PermissionRequest.RESOURCE_VIDEO_CAPTURE)) {
                        if (ContextCompat.checkSelfPermission(this@HybridWebViewActivity, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED) {
                            request.grant(request.resources)
                        } else {
                            request.deny()
                            cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
                        }
                    } else {
                        request.deny()
                    }
                }
            }
        }
    }

    override fun onCameraRequested() {
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED) {
            webView.evaluateJavascript(
                "window.dispatchEvent(new CustomEvent('native-camera-requested', { detail: { granted: true } }));",
                null
            )
        } else {
            webView.evaluateJavascript(
                "window.dispatchEvent(new CustomEvent('native-camera-requested', { detail: { granted: false } }));",
                null
            )
        }
    }

    override fun onGetStorage(key: String): String? = storage.getString(key, null)

    override fun onSetStorage(key: String, value: String) {
        storage.edit().putString(key, value).apply()
    }

    override fun onClearStorage() {
        storage.edit().clear().apply()
    }

    override fun onPushNotificationRequested(title: String, body: String) {
        webView.post {
            webView.evaluateJavascript(
                "window.dispatchEvent(new CustomEvent('native-push-notification-requested', { detail: { title: ${title.asJsString()}, body: ${body.asJsString()} } }));",
                null
            )
        }
    }

    override fun onDestroy() {
        if (::webView.isInitialized) {
            webView.apply {
                removeJavascriptInterface("AndroidBridge")
                loadUrl("about:blank")
                removeAllViews()
                destroy()
            }
        }
        super.onDestroy()
    }

    private fun String.asJsString(): String = "\"" + replace("\\", "\\\\").replace("\"", "\\\"").replace("\n", "\\n").replace("\r", "\\r") + "\""
}

class AndroidBridge(private val listener: NativeBridgeListener) {
    @JavascriptInterface
    fun requestCameraAccess() {
        listener.onCameraRequested()
    }

    @JavascriptInterface
    fun getStorage(key: String): String? {
        return listener.onGetStorage(key)
    }

    @JavascriptInterface
    fun setStorage(key: String, value: String) {
        listener.onSetStorage(key, value)
    }

    @JavascriptInterface
    fun clearStorage() {
        listener.onClearStorage()
    }

    @JavascriptInterface
    fun requestPushNotification(title: String, body: String) {
        listener.onPushNotificationRequested(title, body)
    }
}